import React, { Component } from "react";
import ReactDOM from 'react-dom'
import { Link } from 'react-router-dom';

import { Table, Layout, DatePicker, Card, Col, Row, Avatar, Icon, Divider } from "antd";

import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from "recharts";
import "./../../styles/login.css";

import moment from "moment";
import api from "../../services/Api";


class SpaceSelect extends Component<any, any> {
    constructor(props: any) {
        super(props);
        this.state = {
            spaceList: [],
            folderList: [],
            lists: []

        };
        this.getSpaceList();
    }

    componentDidMount() {

    }

    componentWillMount() {
        document.title = " درمانکده | انتخاب اسپرینت ";
    }

    getSpaceList = async () => {
        let res = await api.getSpaceList(2495317)
        this.setState({ spaceList: res.data.spaces })
    }

    getFolderList = async (id: any) => {
        this.setState({ folderList: [], lists: [] })
        let res = await api.getFolderList(id)
        this.setState({ folderList: res.data.folders })
    }

    getAllLists = async (id: any) => {
        this.setState({ lists: [] })
        let res = await api.getAllLists(id)
        console.log(res.data)
        this.setState({ lists: res.data.lists })
    }

    render() {


        return (
            <div>
                <Divider>Spaces</Divider>
                <Row gutter={5} style={{ marginBottom: 20 }}>
                    {this.state.spaceList.map((item: any, i: any) => {
                        return (<div>
                            <Col xs={24} sm={24} md={4} lg={4} xl={4} style={{ textAlign: 'center', marginBottom: 5 }}>
                                <a onClick={() => { this.getFolderList(item.id) }}>
                                    <Card title="Space" size='small' headStyle={{ backgroundColor: '#556cd6', color: 'white' }} bordered={true}>
                                        {item.name}
                                    </Card>
                                </a>
                            </Col>
                        </div>
                        )
                    })}
                </Row>

                {
                    this.state.folderList.length != 0 ?
                        <div>
                            <Divider>Folders</Divider>
                            <Row gutter={5} style={{ marginBottom: 20 }}>
                                {this.state.folderList.map((item: any, i: any) => {
                                    return (<div>
                                        <Col xs={24} sm={24} md={4} lg={4} xl={4} style={{ textAlign: 'center', marginBottom: 5 }}>
                                            <a onClick={() => { this.getAllLists(item.id) }}>
                                                <Card title="Folder" size='small' headStyle={{ backgroundColor: '#556cd6', color: 'white' }} bordered={true}>
                                                    {item.name}
                                                </Card>
                                            </a>
                                        </Col>
                                    </div>
                                    )
                                })}
                            </Row>
                        </div>
                        : <div />
                }

                {
                    this.state.lists.length != 0 ?
                        <div>
                            <Divider>Lists</Divider>
                            <Row gutter={5} style={{ marginBottom: 20 }}>
                                {this.state.lists.map((item: any, i: any) => {
                                    return (<div>
                                        <Col xs={24} sm={24} md={4} lg={4} xl={4} style={{ textAlign: 'center', marginBottom: 5 }}>
                                            <Link to={"/dashboard/" + item.id}>
                                                <Card title="List" size='small' headStyle={{ backgroundColor: '#556cd6', color: 'white' }} bordered={true}>
                                                    {item.name}
                                                </Card>
                                            </Link>
                                        </Col>
                                    </div>
                                    )
                                })}
                            </Row>
                        </div>
                        : <div />
                }
            </div>
        );
    }
}

export default SpaceSelect;
