import React, { Component } from "react";
import { Table, Layout, DatePicker, Card, Col, Row, Avatar, Icon } from "antd";

import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from "recharts";
import "./../../styles/login.css";

import moment from "moment";
import api from "../../services/Api";

class Team extends Component<any, any> {
    constructor(props: any) {
        super(props);
        this.state = {
            team: [],
            teamList: [],
            loading: true
        };
        this.getTeamList();
    }

    componentDidMount() {

    }

    componentWillMount() {
        document.title = " درمانکده | تیم ";
    }

    getTeamList = async () => {
        let data: any = []
        let res = await api.getTeamList()
        data = res.data.teams[0].members

        data.sort((a: any, b: any) => {
            let t1: any = moment.unix(a.user.last_active),
                t2: any = moment.unix(b.user.last_active)

            return (t2 - t1)
        });
        this.setState({ teamList: data, loading: false })

    }

    render() {
        const columns = [
            {
                title: 'عکس',
                dataIndex: 'user.profilePicture',
                key: 'user.profilePicture',
                render: (profilePicture: any) =>
                    (
                        profilePicture != null ?
                            <div>
                                <Avatar size={32} src={profilePicture} />
                            </div>
                            :
                            <Avatar size={32} icon={<Icon type="user" />} />
                    )

            },
            {
                title: 'نام کاربری',
                dataIndex: 'user.username',
                key: 'user.username',

            },
            {
                title: 'ایمیل',
                dataIndex: 'user.email',
                key: 'user.email',

            },
            {
                title: 'آخرین فعالیت',
                dataIndex: 'user.last_active',
                key: 'user.last_active',
                render: (time: any) => {
                    if (time == null) { return "Not active yet" }
                    return moment.unix(time / 1000).format('YYYY/MM/DD HH:mm').toString()
                }
            },


        ];
        return (
            <div>
                <Row>
                    <Table
                        loading={this.state.loading}
                        size={'middle'}
                        pagination={false}
                        dataSource={this.state.teamList}
                        columns={columns} />
                </Row>
            </div>
        );
    }
}

export default Team;
