import React, { Component } from "react";
import ReactDOM from 'react-dom'
import { Link } from 'react-router-dom';

import { Table, Layout, Switch, Card, Col, Row, Avatar, Icon, Divider, Spin } from "antd";
import { ArrowDownOutlined, ArrowUpOutlined } from '@ant-design/icons';

import {
    PieChart, Pie, Cell, ComposedChart, Line, Area, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer
} from 'recharts';

import moment from "moment";
import api from "../../services/Api";


class Dashboard extends Component<any, any> {
    constructor(props: any) {
        super(props);
        this.state = {
            showLoading: true,
            taskList: [],
            id: props.match.params.id,
            taskStatusList: [],
            taskClosed: [],
            storyClosed: [],
            taskSum: 0,
            storyPointSum: 0,
            sprintDate: {},
            normalBurn: [],
            switchState: true,
            taskVelocity: [],
            storyVelocity: []

        };
        this.getSprintDate();
        this.getAllTask();
    }

    componentDidMount() {

    }

    componentWillMount() {
        document.title = " درمانکده | داشبورد ";
    }

    getAllTask = async () => {
        let res = await api.getAllTasks(this.state.id)
        this.setState({ taskList: res.data, showLoading: false }, () => {
            this.calcuteTaskOfEachPerson()
            //this.taskClose()
        })
    }

    getSprintDate = async () => {
        let res = await api.getSprintDate(this.state.id)
        this.setState({ sprintDate: res.data })
    }


    taskClose = () => {
        let { taskList, sprintDate, storyPointSum } = this.state
        let tmp = taskList
        let dataTask: any = [], dataStory: any = []
        let burn: any = []

        if (sprintDate) {
            let startDate: any = moment(sprintDate.startDate);
            let endDate: any = moment(sprintDate.endDate);
            let diff = endDate.diff(startDate, 'days')
            for (let i = 0; i <= diff; i++) {
                dataTask.push({
                    closeDate: moment(startDate, 'YYYY/MM/DD').add(i, 'days').format('YYYY/MM/DD').toString(),
                    count: 0, burnDown: taskList.length - ((taskList.length / diff) * i) < 0 ? 0 :
                        taskList.length - ((taskList.length / diff) * i)
                })

                dataStory.push({
                    closeDate: moment(startDate, 'YYYY/MM/DD').add(i, 'days').format('YYYY/MM/DD').toString(),
                    count: 0, burnDown: storyPointSum - ((storyPointSum / diff) * i) < 0 ? 0 :
                        storyPointSum - ((storyPointSum / diff) * i)
                })
            }
        }

        if (taskList.length != 0) {
            for (let i = 0; i < taskList.length; i++) {
                let findTask
                findTask = dataTask.findIndex((x: any) => x.closeDate == moment.unix(tmp[i].date_closed / 1000).format('YYYY/MM/DD'));
                findTask != -1 ? dataTask[findTask].count++ : tmp[i].date_closed != null ? dataTask.push({ closeDate: moment.unix(tmp[i].date_closed / 1000).format('YYYY/MM/DD'), count: 1 }) : dataTask = dataTask

                let findStory
                findStory = dataStory.findIndex((x: any) => x.closeDate == moment.unix(tmp[i].date_closed / 1000).format('YYYY/MM/DD'));

                if (findStory != -1) {
                    let count = 0
                    for (let j = 0; j < tmp[i].assignees.length; j++) {
                        count += tmp[i].time_estimate / 3600000
                    }
                    dataStory[findStory].count += count
                } else if (tmp[i].date_closed != null) {
                    let count = 0
                    for (let j = 0; j < tmp[i].assignees.length; j++) {
                        count += tmp[i].time_estimate / 3600000
                    }

                    dataStory.push({ closeDate: moment.unix(tmp[i].date_closed / 1000).format('YYYY/MM/DD'), count: count })

                }

            }

            let taskVelocityArr: any = []
            let storyVelocityArr: any = []

            dataTask.sort((a: any, b: any) => {
                let t1: any = moment(a.closeDate), t2: any = moment(b.closeDate)
                return (t1 - t2)
            });

            dataStory.sort((a: any, b: any) => {
                let t1: any = moment(a.closeDate), t2: any = moment(b.closeDate)
                return (t1 - t2)
            });



            let burnTask = 0, burnStory = 0
            for (let i = 0; i < dataTask.length; i++) {
                taskVelocityArr.push({
                    closeDate: dataTask[i].closeDate,
                    count: dataTask[i].count,
                    burnDown: this.state.taskSum / dataTask.length
                })

                storyVelocityArr.push({
                    closeDate: dataStory[i].closeDate,
                    count: dataStory[i].count,
                    burnDown: this.state.storyPointSum / dataTask.length
                })

                burnTask += dataTask[i].count
                dataTask[i].count = this.state.taskSum - burnTask

                burnStory += dataStory[i].count
                dataStory[i].count = this.state.storyPointSum - burnStory

            }

            this.setState({
                taskClosed: dataTask,
                storyClosed: dataStory,
                taskVelocity: taskVelocityArr,
                storyVelocity: storyVelocityArr
            })

        }
    }


    calcuteTaskOfEachPerson = () => {
        let { taskList } = this.state
        let tmp = taskList
        let data: any = [], status: any = [], sumPoint = 0
        if (taskList.length != 0) {
            for (let i = 0; i < taskList.length; i++) {
                let find, point = 0
                for (let j = 0; j < taskList[i].assignees.length; j++) {
                    find = data.findIndex((x: any) => x.name === tmp[i].assignees[j].username);
                    if (find != -1) {
                        data[find].count++
                        data[find].point += tmp[i].time_estimate / 3600000
                        sumPoint += tmp[i].time_estimate / 3600000
                        point += tmp[i].time_estimate / 3600000
                    } else {
                        sumPoint += tmp[i].time_estimate / 3600000
                        point += tmp[i].time_estimate / 3600000
                        data.push({
                            name: tmp[i].assignees[j].username,
                            point: tmp[i].time_estimate / 3600000,
                            count: 1,
                            color: "#" + ((1 << 24) * Math.random() | 0).toString(16)
                        })
                    }
                }

                let statusFind
                statusFind = status.findIndex((x: any) => x.name === tmp[i].status.status);
                //statusFind != -1 ? status[statusFind].count++ : status.push({ name: tmp[i].status.status, count: 1, color: tmp[i].status.color })

                if (statusFind != -1) {
                    status[statusFind].count++
                    status[statusFind].point += point

                } else {
                    status.push({
                        name: tmp[i].status.status,
                        count: 1,
                        color: tmp[i].status.color,
                        point: point
                    })
                }
            }

            this.setState({
                taskOfEachPerson: data,
                taskStatusList: status,
                taskSum: taskList.length,
                storyPointSum: sumPoint
            }, () => { this.taskClose() })
        }
    }


    render() {
        const CustomTooltip = ({ active, payload, label }: any) => {
            if (active) {
                return (
                    <Card title={payload[0].name} size="small" headStyle={{ backgroundColor: '#556cd6', color: 'white' }} bordered={true}>
                        {payload[0].value}<br />
                        {((payload[0].value * 100) / this.state.taskSum).toFixed(2)}%
                    </Card>
                );
            }
            return null;
        };

        return (
            <div>
                {this.state.taskStatusList.length != 0 ?
                    <div >
                        <div className={'forceltr'} >
                            <Divider>Tasks status</Divider>
                            <Row justify="space-between" align="middle" gutter={{ xs: 8, sm: 16, md: 24, lg: 32 }}>

                                <Col xs={24} sm={24} md={12} lg={12} xl={12} style={{ textAlign: 'center' }}>
                                    <Card title="Task status share" size='small' headStyle={{ backgroundColor: '#556cd6', color: 'white', fontSize: 12 }} bordered={true}>
                                        <div className={'forceltr'} style={{ width: '100%', height: 250 }}>
                                            <ResponsiveContainer>
                                                <PieChart width={400} height={250}>
                                                    <Pie dataKey="point" isAnimationActive={true}
                                                        labelLine={false}
                                                        label={({
                                                            cx, cy, midAngle, innerRadius, outerRadius, percent, index
                                                        }: any) => {
                                                            const RADIAN = Math.PI / 180;
                                                            const radius = innerRadius + (outerRadius - innerRadius) * 0.3;
                                                            const x = cx + radius * Math.cos(-midAngle * RADIAN);
                                                            const y = cy + radius * Math.sin(-midAngle * RADIAN);
                                                            return (
                                                                <text x={x} y={y} fill="white" textAnchor={x > cx ? 'start' : 'end'} dominantBaseline="central">
                                                                    {`${(percent * 100).toFixed(0)}%` /* + `${this.state.taskStatusList[index].name}` */}
                                                                </text>
                                                            );
                                                        }}
                                                        data={this.state.taskStatusList}
                                                        cx="50%"
                                                        cy="50%"
                                                        outerRadius="95%"
                                                        fill="#8884d8" >
                                                        {this.state.taskStatusList.map((entry: any, index: any) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                                                    </Pie>
                                                    <Tooltip />
                                                    <Legend />
                                                </PieChart>
                                            </ResponsiveContainer>
                                        </div>
                                    </Card>
                                </Col>

                                <Col xs={24} sm={24} md={12} lg={12} xl={12} style={{ textAlign: 'center' }}>
                                    <Card title="Task status" size='small' headStyle={{ backgroundColor: '#556cd6', color: 'white', fontSize: 12 }} bordered={true}>
                                        <Table
                                            size={'middle'}
                                            pagination={false}
                                            dataSource={this.state.taskStatusList}
                                            style={{ height: 250, width: '95%' }}
                                            columns={[
                                                {
                                                    title: 'Count',
                                                    dataIndex: 'count',
                                                    key: 'count',
                                                },
                                                {
                                                    title: 'Point',
                                                    dataIndex: 'point',
                                                    key: 'point',
                                                },
                                                {
                                                    title: 'Task status',
                                                    dataIndex: 'name',
                                                    key: 'name',
                                                }
                                            ]} />
                                    </Card>
                                </Col>
                            </Row>

                            <Divider>Team Story point</Divider>
                            <Row justify="space-between" align="middle" gutter={{ xs: 2, sm: 16, md: 10, lg: 10 }}>
                                {this.state.taskOfEachPerson.map((item: any, i: any) => {
                                    return (
                                        <Col xs={8} sm={8} md={12} lg={3} xl={3} style={{ textAlign: 'center', marginTop: 5 }}>
                                            <Card title={item.name} size='small' headStyle={{ backgroundColor: '#556cd6', color: 'white', fontSize: 12 }} bordered={true}>
                                                {item.point}
                                            </Card>
                                        </Col>)
                                })}
                            </Row>

                            <Divider />
                            <Row className={'forceltr'} justify="space-between" align="middle" gutter={{ xs: 8, sm: 16, md: 24, lg: 32 }}>
                                <Col xs={24} sm={24} md={24} lg={24} xl={24} style={{ margin: 5 }}>
                                    <div style={{ width: '100%', height: 400 }}>
                                        <ResponsiveContainer>
                                            <ComposedChart
                                                width={800}
                                                height={400}
                                                data={this.state.taskOfEachPerson}
                                                margin={{
                                                    top: 2, right: 5, bottom: 2, left: -25,
                                                }}
                                            >
                                                <CartesianGrid stroke="#f5f5f5" />
                                                <XAxis dataKey="name" />
                                                <YAxis />
                                                <Tooltip />
                                                {/* <Legend /> */}
                                                {/* <Area type="monotone" dataKey="amt" fill="#8884d8" stroke="#8884d8" /> */}
                                                <Bar dataKey="count" barSize={10} fill="#413ea0" />
                                                <Line type="monotone" dataKey="point" stroke="#ff7300" strokeWidth={3} />
                                            </ComposedChart>
                                        </ResponsiveContainer>
                                    </div>
                                </Col>
                            </Row>

                            <Divider>{this.state.switchState ? "Task" : "Story"} BurnDown chart</Divider>
                            <div>
                                <Switch
                                    onClick={(state) => {
                                        this.setState({ switchState: state })
                                    }}

                                    checkedChildren="Task"
                                    unCheckedChildren="Story"
                                    defaultChecked={this.state.switchState}
                                />
                            </div>
                            <Row className={'forceltr'} justify="space-between" align="middle" gutter={{ xs: 8, sm: 16, md: 24, lg: 32 }}>
                                <Col xs={24} sm={24} md={24} lg={24} xl={24} style={{ margin: 5 }}>
                                    <div style={{ width: '100%', height: 400 }}>
                                        <ResponsiveContainer>
                                            <ComposedChart
                                                width={800}
                                                height={400}
                                                data={this.state.switchState ? this.state.taskClosed : this.state.storyClosed}
                                                margin={{
                                                    top: 5, right: 5, bottom: 25, left: -25,
                                                }}
                                            >
                                                <CartesianGrid stroke="#b8b8b8" strokeDasharray="3 3" />
                                                <XAxis dataKey="closeDate" tick={({ x, y, stroke, payload }) => {
                                                    return (
                                                        <g transform={`translate(${x},${y})`}>
                                                            <text x={0} y={0} dy={16} textAnchor="end" fill="#666" transform="rotate(-25)">{payload.value}</text>
                                                        </g>
                                                    );
                                                }} />

                                                <YAxis type="number" tick={({ x, y, stroke, payload }) => {
                                                    return (
                                                        <g transform={`translate(${x},${y})`}>
                                                            <text x={0} y={0} dy={16} textAnchor="end" fill="#666">{Math.abs(payload.value.toFixed(0))}</text>
                                                        </g>
                                                    );
                                                }} />

                                                <Tooltip content={
                                                    ({ active, payload, label }: any) => {
                                                        if (active) {
                                                            return (
                                                                <Card title={label} size="small" headStyle={{ backgroundColor: '#556cd6', color: 'white' }} bordered={true}>
                                                                    Remaining {this.state.switchState ? "Task" : "Story"}: {payload[0].payload.count}<br />
                                                                    Planned {this.state.switchState ? "Task" : "Story"}: {Math.abs(payload[0].payload.burnDown.toFixed(0))}<br />
                                                                    Status: {payload[0].payload.count - Math.abs(payload[0].payload.burnDown.toFixed(0)) <= 0 ? <ArrowUpOutlined style={{ color: 'green' }} /> : <ArrowDownOutlined style={{ color: 'red' }} />}
                                                                </Card>
                                                            );
                                                        }
                                                        return null;
                                                    }
                                                } />
                                                {/* <Legend /> */}
                                                {/*  <Bar dataKey="taskCount" barSize={20} fill="#413ea0" /> */}
                                                {/* <Line type="monotone" dataKey="burnDown" stroke="#413ea0" /> */}
                                                <Area type="monotone" dataKey="burnDown" fill="#8884d8" stroke="#8884d8" />
                                                <Line type="monotone" dataKey="count" stroke="#ff7300" strokeWidth={3} dot={(props) => {
                                                    const { cx, cy, stroke, payload, value }: any = props
                                                    if (payload.closeDate == moment().format('YYYY/MM/DD')) {
                                                        return (<circle r="3" type="monotone" stroke="#ff7300" stroke-width="5" fill="#ff7300" width="343" height="330" cx={cx} cy={cy} className="recharts-dot recharts-line-dot"></circle>)
                                                    } else {
                                                        return (<circle r="3" type="monotone" stroke="#ff7300" stroke-width="1" fill="#fff" width="343" height="330" cx={cx} cy={cy} className="recharts-dot recharts-line-dot"></circle>)
                                                    }
                                                }} />
                                            </ComposedChart>
                                        </ResponsiveContainer>
                                    </div>
                                </Col>
                            </Row>

                            <Divider>{this.state.switchState ? "Task" : "Story"} Velocity</Divider>
                            <Row className={'forceltr'} justify="space-between" align="middle" gutter={{ xs: 8, sm: 16, md: 24, lg: 32 }}>
                                <Col xs={24} sm={24} md={24} lg={24} xl={24} style={{ margin: 5 }}>
                                    <div style={{ width: '100%', height: 400 }}>
                                        <ResponsiveContainer>
                                            <ComposedChart
                                                width={800}
                                                height={400}
                                                data={this.state.switchState ? this.state.taskVelocity : this.state.storyVelocity}
                                                margin={{
                                                    top: 5, right: 5, bottom: 25, left: -25,
                                                }}
                                            >
                                                <CartesianGrid stroke="#b8b8b8" strokeDasharray="3 3" />
                                                <XAxis dataKey="closeDate" tick={({ x, y, stroke, payload }) => {
                                                    return (
                                                        <g transform={`translate(${x},${y})`}>
                                                            <text x={0} y={0} dy={16} textAnchor="end" fill="#666" transform="rotate(-25)">{payload.value}</text>
                                                        </g>
                                                    );
                                                }} />

                                                <YAxis type="number" tick={({ x, y, stroke, payload }) => {
                                                    return (
                                                        <g transform={`translate(${x},${y})`}>
                                                            <text x={0} y={0} dy={16} textAnchor="end" fill="#666">{Math.abs(payload.value.toFixed(0))}</text>
                                                        </g>
                                                    );
                                                }} />

                                                <Tooltip content={
                                                    ({ active, payload, label }: any) => {
                                                        if (active) {
                                                            return (
                                                                <Card title={label} size="small" headStyle={{ backgroundColor: '#556cd6', color: 'white' }} bordered={true}>
                                                                    Doing {this.state.switchState ? "Task" : "Story"}: {payload[0].payload.count}<br />
                                                                    Avg {this.state.switchState ? "Task" : "Story"}: {Math.abs(payload[0].payload.burnDown.toFixed(0))}<br />
                                                                    Status: {payload[0].payload.count - Math.abs(payload[0].payload.burnDown.toFixed(0)) >= 0 ? <ArrowUpOutlined style={{ color: 'green' }} /> : <ArrowDownOutlined style={{ color: 'red' }} />}
                                                                </Card>
                                                            );
                                                        }
                                                        return null;
                                                    }
                                                } />
                                                {/* <Legend /> */}
                                                <Bar dataKey="count" barSize={10} fill="#413ea0" />
                                                {/* <Line type="monotone" dataKey="burnDown" stroke="#413ea0" /> */}
                                                {/* <Area type="monotone" dataKey="burnDown" fill="#8884d8" stroke="#8884d8" /> */}
                                                <Line type="monotone" dataKey="burnDown" stroke="#ff7300" strokeWidth={3} dot={(props) => {
                                                    const { cx, cy, stroke, payload, value }: any = props
                                                    if (payload.closeDate == moment().format('YYYY/MM/DD')) {
                                                        return (<circle r="3" type="monotone" stroke="#ff7300" stroke-width="5" fill="#ff7300" width="343" height="330" cx={cx} cy={cy} className="recharts-dot recharts-line-dot"></circle>)
                                                    } else {
                                                        return (<circle r="3" type="monotone" stroke="#ff7300" stroke-width="1" fill="#fff" width="343" height="330" cx={cx} cy={cy} className="recharts-dot recharts-line-dot"></circle>)
                                                    }
                                                }} />
                                            </ComposedChart>
                                        </ResponsiveContainer>
                                    </div>
                                </Col>
                            </Row>



                            <Divider />
                            <Row gutter={{ xs: 8, sm: 16, md: 24, lg: 32 }}>
                                <Col xs={24} sm={24} md={12} lg={12} xl={12} style={{ textAlign: 'center' }}>
                                    <Card title="Task share" size='small' headStyle={{ backgroundColor: '#556cd6', color: 'white', fontSize: 12 }} bordered={true}>
                                        <div className={'forceltr'} style={{ width: '100%', height: 220 }}>
                                            <ResponsiveContainer>
                                                <PieChart width={400} height={400}>
                                                    <Pie dataKey="count"
                                                        valueKey="name"
                                                        isAnimationActive={false}
                                                        labelLine
                                                        label={(entry: any) => { return entry.name }}
                                                        data={this.state.taskOfEachPerson}
                                                        cx="50%"
                                                        cy="50%"
                                                        outerRadius="50%"
                                                        fill="#8884d8" >
                                                        {this.state.taskOfEachPerson.map((entry: any, index: any) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                                                    </Pie>
                                                    <Tooltip content={<CustomTooltip />} />
                                                </PieChart>
                                            </ResponsiveContainer>
                                        </div>
                                    </Card>
                                </Col>

                                <Col xs={24} sm={24} md={12} lg={12} xl={12} style={{ textAlign: 'center' }}>
                                    <Card title="Story point share" size='small' headStyle={{ backgroundColor: '#556cd6', color: 'white', fontSize: 12 }} bordered={true}>
                                        <div className={'forceltr'} style={{ width: '100%', height: 220 }}>
                                            <ResponsiveContainer>
                                                <PieChart width={400} height={400}>
                                                    <Pie dataKey="point"
                                                        valueKey="name"
                                                        isAnimationActive={false}
                                                        labelLine
                                                        label={(entry: any) => { return entry.name }}
                                                        data={this.state.taskOfEachPerson}
                                                        cx="50%"
                                                        cy="50%"
                                                        outerRadius="50%"
                                                        fill="#8884d8" >
                                                        {this.state.taskOfEachPerson.map((entry: any, index: any) => <Cell key={`cell-${index}`} fill={entry.color} />)}
                                                    </Pie>
                                                    <Tooltip content={({ active, payload, label }: any) => {
                                                        if (active) {
                                                            return (
                                                                <Card title={payload[0].name} size="small" headStyle={{ backgroundColor: '#556cd6', color: 'white' }} bordered={true}>
                                                                    {payload[0].value}<br />
                                                                    {((payload[0].value * 100) / this.state.storyPointSum).toFixed(2)}%
                                                                </Card>
                                                            );
                                                        }
                                                        return null;
                                                    }} />
                                                </PieChart>
                                            </ResponsiveContainer>
                                        </div>
                                    </Card>
                                </Col>
                            </Row>
                        </div>
                    </div>
                    :
                    <div style={{
                        textAlign: 'center', borderRadius: '4px',
                        marginBottom: '20px', padding: '30px 50px', margin: '200px 0'
                    }}>
                        < Spin spinning={this.state.showLoading} tip="لطفا چند لحظه صبر کنید ...." style={{ textAlign: 'center' }}></Spin>
                    </div >
                }
            </div>
        );
    }
}
export default Dashboard;
