import React, { Component } from 'react';
import { Link } from 'react-router-dom';
import { PageHeader } from 'antd'

import { Layout, Menu, Icon, Badge } from 'antd';
import './../../styles/login.css';

const { Header, Content, Footer, Sider } = Layout;



class Master extends Component<any, any> {

    constructor(props: any) {
        super(props);
        this.state = {
            collapsed: true,
        }
    }

    componentWillMount() {
        document.title = "درمانکده";
    }

    toggle = () => {
        this.setState({
            collapsed: !this.state.collapsed,
        });
    };

    render() {


        return (
            <div>


                <Layout>
                    <Sider trigger={null} collapsible collapsed={this.state.collapsed} style={{ width: '50px' }}>
                        <div className="logo" />
                        <Menu theme="dark" mode="inline" defaultSelectedKeys={['1']} style={{ height: '100vh' }}>
                            <Header style={{ background: '#00000', padding: 0, paddingRight: 5 }}>
                                <div style={{ textAlign: 'center' }}>
                                    <Link to="/home" style={{ color: 'white' }}>
                                        درمانکده
                                    </Link>
                                </div>
                            </Header>

                            <Menu.Item key="1">
                                <Icon type="home" style={{ marginLeft: 8 }} />
                                <span>صفحه اصلی</span>
                                <Link to="/home" />
                            </Menu.Item>
                            <Menu.Item key="2">
                                <Icon type="user" style={{ marginLeft: 8 }} />
                                <span>تیم</span>
                                <Link to="/team" />
                            </Menu.Item>
                            <Menu.Item key="3">
                                <Icon type="upload" style={{ marginLeft: 8 }} />
                                <span>داشبورد</span>
                                <Link to="/dashboard" />
                            </Menu.Item>
                           {/*  <Menu.Item key="4">
                                <Icon type="upload" style={{ marginLeft: 8 }} />
                                <span>مانیتور</span>
                            </Menu.Item> */}
                        </Menu>
                    </Sider>
                    <Layout>
                        <PageHeader
                            ghost={false}
                            title={<Badge dot={true}><Icon type={'user'} /></Badge>}
                            extra={[<Icon
                                className="trigger"
                                type={this.state.collapsed ? 'menu-unfold' : 'menu-fold'}
                                onClick={this.toggle} />]}
                        />

                        <Content
                            style={{
                                margin: '24px 16px',
                                padding: 24,
                                background: '#fff',
                                minHeight: 280,
                            }}
                        >
                            {this.props.children}
                        </Content>
                    </Layout>
                </Layout>
            </div>
        );
    }
}

export default Master;

