import React, { Component } from 'react';
import { Input, Spin, Icon, Form, Row, Col, notification } from 'antd';
import { Button } from 'antd';
import { Card } from 'antd';
import { DatePicker } from 'antd';
import locale from 'antd/es/date-picker/locale/fa_IR';
import api from "../../services/Api"
import cookie from 'react-cookies'

import './../../styles/login.css';
const style = {
    cardHeader: {
        backgroundColor: '#1890ff',
        color: 'white',
        borderRadius: '5px 5px 0 0 '
    }
}


class Login extends Component<any, any> {

    constructor(props: any) {
        super(props);
        this.state = {
            loading: false,
            userName: '',
            password: ''
        }
    }


    componentDidMount() {
        document.title = " درمانکده | ورود ";
    }


    login = async () => {
        this.setState({ loading: true });
        let { userName, password } = this.state
        let res = await api.login(userName, password)
        console.log(res)
        res.data == "ok" ? this.setState({ loading: false }) : this.setState({ loading: false })

        if (res.data == "ok") {
            const expires = new Date()
            expires.setHours(expires.getHours() + 24)
            let data =
            {
                path: '/',
                expires,
                //maxAge: 1000,
                /* domain: 'https://play.bukinoshita.io',
                secure: true
                httpOnly: true */
            }

            cookie.save('info', 'ok', data)
            this.setState({ loading: false })
            this.props.history.push('/home')
        } else {
            this.openNotification()
        }
    }

    openNotification = () => {
        const key = `open${Date.now()}`
        notification.info({
            message: "خطا",
            description: "اطلاعات کاربری صحیح نمی باشد.",
            placement: "topRight",
            duration: 0,
            key,
            onClick() {
                console.log('click')
                notification.close(key)
            }
        });
    };

    onValueChange = (value: any) => {
        console.log(value.target.value)
    };

    render() {
        const { getFieldDecorator } = this.props.form;



        return (
            <div style={{ width: '100%' }}>
                <div className={'container'} >
                    <Card title="ورود" size='small'
                        headStyle={style.cardHeader}
                        className={'card'}>
                        <Form labelAlign="left" style={{ margin: 10 }}>
                            <Spin tip="لطفا چند لحظه ..." spinning={this.state.loading}>
                                <Row>
                                    <Col span={21} >
                                        <Form.Item  >
                                            {getFieldDecorator('نام کاربری', {
                                                rules: [{ required: true, message: 'نام کاربری اجباری می باشد' }],
                                            })(<Input placeholder="لطفا نام کاربری را وارد کنید" className={'input'}
                                                onChange={(value: any) => {
                                                    this.setState({ userName: value.target.value })
                                                }}
                                            />,
                                            )}
                                        </Form.Item>
                                    </Col>
                                    <Col span={3}>
                                        <div style={{
                                            textAlign: 'center',
                                            marginTop: '10px',
                                            height: '40px',
                                            display: 'flex',
                                            alignItems: 'center'
                                        }}>
                                            <span>نام کاربری:</span>
                                        </div>

                                    </Col>
                                </Row>

                                <Row>
                                    <Col span={21}>
                                        <Form.Item  /* label="کلمه عبور" */>
                                            {getFieldDecorator('کلمه عبور', {
                                                rules: [{ required: true, message: 'کلمه عبور اجباری می باشد' }],
                                            })(
                                                <Input.Password
                                                    className={'input'}
                                                    type="password"
                                                    placeholder='لطفا کلمه عبور را وارد کنید!'
                                                    onChange={(value: any) => {
                                                        this.setState({ password: value.target.value })

                                                    }}
                                                    onKeyPress={(ev: any) => { ev.key == "Enter" ? this.login() : ev = ev }}
                                                />,
                                            )}
                                        </Form.Item>
                                    </Col>
                                    <Col span={3}>
                                        <div style={{
                                            textAlign: 'center',
                                            marginTop: '10px',
                                            height: '40px',
                                            display: 'flex',
                                            alignItems: 'center'
                                        }}>
                                            <span>کلمه عبور:</span>
                                        </div>

                                    </Col>
                                </Row>

                                <div className={'noRtl btn'} >
                                    <Button type="primary" /* loading */ size='large' block style={{ width: '80%' }}
                                        onClick={() => {
                                            this.login()
                                        }}
                                    >
                                        ورود
                                    </Button>
                                </div>

                            </Spin>
                        </Form>

                    </Card>

                </div>

            </div >
        );
    }
}

const WrappedLogin = Form.create()(Login)
export default WrappedLogin;
//export default Login;

