import React, { Component } from 'react';
import { BrowserRouter, Route, Switch, Redirect, Link } from 'react-router-dom';
import cookie from 'react-cookies'

import Login from '../views/public/login';
import HomePublic from "../views/public/home";

//import test from "../views/private/master"
import Master from '../views/private/master';
import Chart from '../views/private/chart';
import Team from '../views/private/team';
import SpaceSelect from "../views/private/spaceSelect"
import Dashboard from "../views/private/dashboard"
import HomePrivate from "../views/private/home"


import api from "../services/Api";



const loading = () => <div className="animated fadeIn pt-3 text-center">Loading...</div>;


class Router extends Component {

    RouteLayout({ layout, component, path, auth, ...rest }: any) {
        let check = false
        if (auth) {
            cookie.load('info') == 'ok' ? check = true : check = false
            
        }

        if (check != false || !auth) {
            return path && layout ? (
                <Route {...rest} render={(props) =>
                    React.createElement(layout, props, React.createElement(component, props))
                } />)
                : (
                    <Route {...rest} render={(props) =>
                        React.createElement(component, props)
                    } />
                )
        } else {
            //need makde auth check
            return <Redirect
                to={{
                    pathname: "/login",
                    state: { from: 'location' }
                }}
            />
        }
    }

    render() {
        var Route = this.RouteLayout
        return (
            <BrowserRouter>
                <React.Suspense fallback={loading()}>
                    <Switch>
                        {/* public */}
                        <Route exact path="/" name="index Page" component={HomePublic} />
                        <Route exact path="/login" name="login Page" component={Login} />

                        {/* private */}
                        <Route exact path="/home" name="index Page" component={HomePrivate} layout={Master} auth />
                        <Route exact path="/chart" name="index Page" component={Chart} layout={Master} auth />
                        <Route exact path="/team" name="team" component={Team} layout={Master} auth />

                        <Route exact path="/dashboard" name="dashboad select" component={SpaceSelect} layout={Master} auth />
                        <Route exact path="/dashboard/:id" name="dashboard" component={Dashboard} layout={Master} auth />


                        {/* <Route exact path="/users" name="Users Page" component={Users} auth /> */}

                        {/* 404 */}
                        <Route name="default" component={NotFound} />



                    </Switch>
                </React.Suspense>
            </BrowserRouter>
        );
    }
}

export default Router;



function NotFound() {
    return (<div style={{
        width: '100%',
        minHeight: '100vh',
        display: 'flex',
        flexWrap: 'wrap',
        justifyContent: 'center',
        alignItems: 'center',
    }}>
        <div style={{ display: 'table', textAlign: 'center' }}>
            <p style={{ fontSize: '40px' }}>404</p>
            <p style={{ fontSize: '30px' }}>.اوه! اینجا چیزی نیستش</p>
            <Link to="/">برو خونه</Link>
        </div>

    </div >);
}

function Users() {
    return <h2>Users</h2>;
}

function Index() {

    return <div>
        <h2>Index</h2>
        <Link to="/chart">چارت</Link><br />
        <Link to="/team">تیم</Link><br />
        <Link to="/dashboard">داشبورد</Link>


        <span>اسپرینت جاری</span><br />
        

    </div>;
}