import React, { Component } from "react";
import { Table, Layout, DatePicker, Card, Col, Row } from "antd";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from "recharts";
import "./../../styles/login.css";

import moment from "moment";
import api from "../../services/Api";

class Chart extends Component<any, any> {
    constructor(props: any) {
        super(props);
        this.state = {
            response: [],
            gridData: []
        };
    }

    componentDidMount() {
        this.getTaskList();
    }

    // componentWillMount() {
    //     document.title = "درمانکده";
    // }

    getTaskList = async () => {
        let res = await api.getAllTasks(15265591, '?archived=false&page=1&subtasks=true&include_closed=true')
        console.log(res)
    }


    avg = () => {
        let avg = 0;
        if (this.state.response.length != 0) {
            for (let i = 0; i < this.state.response.length; i++) {
                avg = avg + this.state.response[i].duration;
            }
        }
        var display = moment
            .utc(
                moment
                    .duration(avg / this.state.response.length, "seconds")
                    .asMilliseconds()
            )
            .format("HH:mm:ss");

        return this.state.response.length ? display : 0;
    };

    render() {
        const { MonthPicker, RangePicker } = DatePicker;
        const dateFormat = "YYYY/MM/DD";
        const monthFormat = "YYYY/MM";
        const dateFormatList = ["DD/MM/YYYY", "DD/MM/YY"];
        const margin = {
            top: 60,
            bottom: 60,
            left: 80,
            right: 80
        };

        return (
            <div>
                <Row gutter={16} style={{ marginBottom: 5 }}>
                    <Col span={16}>
                        <div className={"forceltr"}>
                            <LineChart
                                width={700}
                                height={300}
                                data={this.state.gridData}
                            >
                                <CartesianGrid strokeDasharray="5 5" />
                                <XAxis dataKey="hour" label="ساعت" />
                                <YAxis />
                                <Tooltip />
                                {/* <Legend /> */}
                                <Line
                                    type="monotone"
                                    dataKey="count"
                                    stroke="#8884d8"
                                    activeDot={{ r: 8 }}
                                />
                            </LineChart>
                        </div>
                    </Col>
                </Row>
            </div>
        );
    }
}

export default Chart;
