import React, { Component } from "react";
import { Table, Layout, DatePicker, Card, Col, Row } from "antd";
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend } from "recharts";
import "./../../styles/login.css";
import { Link } from 'react-router-dom';

import moment from "moment";
import api from "../../services/Api";

class Home extends Component<any, any> {
    constructor(props: any) {
        super(props);
        this.state = {
            currentSprint: 0
        };
    }

    componentDidMount() {
        this.getCurrentSprint();
    }

    // componentWillMount() {
    //     document.title = "درمانکده";
    // }

    getCurrentSprint = async () => {
        let res = await api.getCurrentSprint()
        this.setState({ currentSprint: res.data })
    }

    render() {
        return (
            <div>
                <Row gutter={16} style={{ marginBottom: 5 }}>
                    <Col span={24}>
                        <Link to="/dashboard">داشبورد</Link><br />
                        <Link to={"/dashboard/" + this.state.currentSprint}>اسپرینت جاری</Link>

                    </Col>
                </Row>
            </div>
        );
    }
}

export default Home;
