import axios from 'axios';

export default class DataStore {

    private static config: any = {
        headers: {
            'Accept': 'application/json',
            'Content-Type': 'application/json',
            'cache-control': 'no-cache',
            'Authorization': 'pk_4536237_NTTG0X1LT9S3D4QOH5FD16UC6B4J9XH4'
        },
        timeout: 30000,
        crossDomain: false
    }

    static async post(url: string, data?: any) {
        try {
            let res = await axios.post(url, data, this.config)
            return (res)
        } catch (error) {
            console.log('ERROR1 URL: ', url);
            throw error
        }
    }

    static async get(url: any) {
        try {
            let res = await axios.get(url, this.config)
            return (res)
        } catch (error) {
            console.log('ERROR1 URL: ', url);
            throw error
        }
    }

}